class Player:    """    Encapsulates abstract player information (ammo, time, score).    """    def __init__(self, username: str, initial_ammo: int, initial_time: float):        self._validate_init(username, initial_ammo, initial_time)        self._username = username        self._ammo = initial_ammo        self._time_remaining = initial_time        self._score = 0        self._combo = 0        self._max_combo = 0        self._glitch_timer = 0.0    def _validate_init(self, username: str, initial_ammo: int, initial_time: float) -> None:        if not isinstance(username, str) or username.strip() == "":            raise ValueError("username must be a non-empty string")        if not isinstance(initial_ammo, int):            raise TypeError("initial_ammo must be an integer")        if initial_ammo <= 0:            raise ValueError("initial_ammo must be positive")        if not isinstance(initial_time, (int, float)):            raise TypeError("initial_time must be a number")        if initial_time <= 0:            raise ValueError("initial_time must be positive")    @property    def username(self) -> str:        return self._username    @property    def ammo(self) -> int:        return self._ammo    @property    def time_remaining(self) -> float:        return self._time_remaining    @property    def score(self) -> int:        return self._score    @property    def combo(self) -> int:        return self._combo    @property    def max_combo(self) -> int:        return self._max_combo    @property    def glitch_timer(self) -> float:        return self._glitch_timer    @property    def is_locked_out(self) -> bool:        return self._ammo <= 0 or self._time_remaining <= 0.0    def fire_shot(self) -> bool:        """Decrease ammo on success."""        if self.is_locked_out:            return False        self._ammo -= 1        return True    def add_ammo(self, amount: int) -> None:        if not isinstance(amount, int):            raise TypeError("amount must be an integer")        if amount <= 0:            raise ValueError("amount must be positive")        self._ammo += amount    def add_time(self, amount: float) -> None:        if not isinstance(amount, (int, float)):            raise TypeError("amount must be a number")        if amount <= 0:            raise ValueError("amount must be positive")        self._time_remaining += amount    def add_score(self, amount: int) -> None:        if not isinstance(amount, (int, float)):            raise TypeError("amount must be a number")        if amount < 0:            raise ValueError("amount cannot be negative")        self._score += amount    def increment_combo(self) -> None:        self._combo += 1        if self._combo > self._max_combo:            self._max_combo = self._combo    def reset_combo(self) -> None:        self._combo = 0    def set_glitch_timer(self, seconds: float) -> None:        if not isinstance(seconds, (int, float)):            raise TypeError("seconds must be a number")        if seconds < 0:            raise ValueError("seconds cannot be negative")        self._glitch_timer = seconds    def update_time(self, dt: float) -> None:        """Decrease time limits when playing."""        if not isinstance(dt, (int, float)):            raise TypeError("dt must be a number")        if dt < 0:            raise ValueError("dt cannot be negative")        if not self.is_locked_out:            self._time_remaining = max(0.0, self._time_remaining - dt)        if self._glitch_timer > 0:            self._glitch_timer = max(0.0, self._glitch_timer - dt)